                                   x.size(2) - weight.size(2) + 1,
                                   x.size(3) - weight.size(3) + 1},
                                   x.options());
    if (bias_opt.has_value()) {
        EXEC_NPU_CMD(aclnnConv2dDivideLeakyReluCustom, x, weight, bias_opt.value(), divisor, result);
    } else {
        // Pass an undefined tensor for optional bias
        at::Tensor none_bias;
        EXEC_NPU_CMD(aclnnConv2dDivideLeakyReluCustom, x, weight, none_bias, divisor, result);
    }
    return result;
}

